// Colored House Component - colors each block based on pillar score
function ColoredHouse({ pillarScores }: { pillarScores: Record<PillarKey, number> | undefined }) {
  if (!pillarScores) return null;
  
  // Get color based on score: >=70 = green, 50-69 = yellow, <50 = red
  const getBlockColor = (score: number) => {
    if (score >= 70) return { fill: '#10b981', label: 'Good' }; // emerald-500
    if (score >= 50) return { fill: '#f59e0b', label: 'Fair' }; // amber-500
    return { fill: '#ef4444', label: 'Needs Work' }; // red-500
  };
  
  const getBlockColorClass = (score: number) => {
    if (score >= 70) return 'fill-emerald-500';
    if (score >= 50) return 'fill-amber-500';
    return 'fill-red-500';
  };
  
  // Map pillars to house blocks (bottom to top, left to right)
  const pillarOrder: PillarKey[] = ['cashFlow', 'income', 'debt', 'protection', 'investments', 'organization', 'direction'];
  const pillarLabels: Record<PillarKey, string> = {
    income: 'Income',
    cashFlow: 'Cash Flow',
    debt: 'Debt',
    protection: 'Protection',
    investments: 'Invest',
    organization: 'Organize',
    direction: 'Direction'
  };
  
  return (
    <div className="relative">
      <svg viewBox="0 0 300 280" className="w-full max-w-md h-auto" style={{ maxHeight: '320px' }}>
        {/* Roof */}
        <polygon points="150,10 280,100 20,100" fill="#1e3a5f" />
        
        {/* Block 1 - Cash Flow (bottom left) */}
        <rect 
          x="30" y="170" width="55" height="70" 
          className={getBlockColorClass(pillarScores.cashFlow || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="57" y="210" textAnchor="middle" fill="white" fontSize="8" fontWeight="bold">CASH</text>
        
        {/* Block 2 - Income (bottom center-left) */}
        <rect 
          x="90" y="170" width="55" height="70" 
          className={getBlockColorClass(pillarScores.income || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="117" y="210" textAnchor="middle" fill="white" fontSize="8" fontWeight="bold">INCOME</text>
        
        {/* Block 3 - Debt (bottom center-right) */}
        <rect 
          x="150" y="170" width="55" height="70" 
          className={getBlockColorClass(pillarScores.debt || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="177" y="210" textAnchor="middle" fill="white" fontSize="7" fontWeight="bold">DEBT</text>
        
        {/* Block 4 - Protection (bottom right) */}
        <rect 
          x="210" y="170" width="55" height="70" 
          className={getBlockColorClass(pillarScores.protection || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="237" y="210" textAnchor="middle" fill="white" fontSize="7" fontWeight="bold">PROTECT</text>
        
        {/* Block 5 - Investments (middle left) */}
        <rect 
          x="50" y="100" width="50" height="65" 
          className={getBlockColorClass(pillarScores.investments || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="75" y="135" textAnchor="middle" fill="white" fontSize="8" fontWeight="bold">INVEST</text>
        
        {/* Block 6 - Organization (middle center) */}
        <rect 
          x="110" y="100" width="80" height="65" 
          className={getBlockColorClass(pillarScores.organization || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="150" y="135" textAnchor="middle" fill="white" fontSize="8" fontWeight="bold">ORGANIZE</text>
        
        {/* Block 7 - Direction (middle right) */}
        <rect 
          x="200" y="100" width="50" height="65" 
          className={getBlockColorClass(pillarScores.direction || 0)}
          stroke="#fff" strokeWidth="2"
        />
        <text x="225" y="135" textAnchor="middle" fill="white" fontSize="7" fontWeight="bold">DIRECT</text>
        
        {/* Foundation */}
        <rect x="20" y="240" width="260" height="25" fill="#374151" stroke="#fff" strokeWidth="1" />
        <text x="150" y="257" textAnchor="middle" fill="white" fontSize="10" fontWeight="bold">FOUNDATION</text>
      </svg>
      
      {/* Legend */}
      <div className="flex justify-center gap-4 mt-3 text-xs">
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 bg-emerald-500 rounded"></div>
          <span>Good (70+)</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 bg-amber-500 rounded"></div>
          <span>Fair (50-69)</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 bg-red-500 rounded"></div>
          <span>Needs Work (&lt;50)</span>
        </div>
      </div>
    </div>
  );
}

