// FREE ASSESSMENT QUESTIONS (10-15 questions)
// =====================================================

export type ConditionOperator = 'equals' | 'not_equals' | 'in' | 'not_in';

export interface QuestionCondition {
  key: string;
  operator: ConditionOperator;
  value: any;
}

export interface Question {
  key: string;
  question: string;
  type: 'single' | 'multiple' | 'number' | 'scale';
  options?: { value: string; label: string }[];
  placeholder?: string;
  helperText?: string;
  section?: BuildingBlockKey;
  required?: boolean;
  conditions?: QuestionCondition[];
}

// Helper function to evaluate a single condition
export function evaluateCondition(
  condition: QuestionCondition,
  responses: Record<string, any>
): boolean {
  const responseValue = responses[condition.key];
  
  // If no response yet, condition is not met (for safety, assume false)
  if (responseValue === undefined || responseValue === null || responseValue === '') {
    return false;
  }
  
  switch (condition.operator) {
    case 'equals':
      return responseValue === condition.value;
    case 'not_equals':
      return responseValue !== condition.value;
    case 'in':
      // For 'in', condition.value should be an array
      if (Array.isArray(condition.value)) {
        return condition.value.includes(responseValue);
      }
      return false;
    case 'not_in':
      // For 'not_in', condition.value should be an array
      if (Array.isArray(condition.value)) {
        return !condition.value.includes(responseValue);
      }
      return true;
    default:
      return false;
  }
}

// Check if all conditions are met for a question
export function evaluateAllConditions(
  conditions: QuestionCondition[],
  responses: Record<string, any>
): boolean {
  if (!conditions || conditions.length === 0) {
    return true; // No conditions means always show
  }
  // ALL conditions must be true (AND logic)
  return conditions.every(c => evaluateCondition(c, responses));
}

// Get visible questions based on conditions
export function getVisibleQuestions(
  questions: Question[],
  responses: Record<string, any>
): Question[] {
  return questions.filter(q => evaluateAllConditions(q.conditions || [], responses));
}

