// Convert answer to score (0-100)
export function scoreAnswer(
  questionKey: string, 
  answer: string | string[] | number
): number {
  const scores: Record<string, Record<string, number>> = {
    incomeStability: {
      very_stable: 100,
      stable: 75,
      somewhat: 50,
      unstable: 25,
    },
    spendingBehavior: {
      very_disciplined: 100,
      disciplined: 75,
      somewhat: 50,
      uncontrolled: 25,
    },
    spendingAwareness: {
      exact: 100,
      general: 75,
      vague: 50,
      no: 25,
    },
    savingsRate: {
      '20_plus': 100,
      '10_20': 75,
      '5_10': 50,
      less_5: 25,
      none: 0,
    },
    automation: {
      yes_auto: 100,
      yes_manual: 50,
      no: 0,
    },
    debtBurden: {
      none: 100,
      manageable: 80,
      comfortable: 60,
      tight: 30,
      struggling: 10,
    },
    emergencyFund: {
      '6_plus': 100,
      '3_6': 75,
      '1_3': 40,
      less_1: 15,
      none: 0,
    },
    insuranceCoverage: {
      comprehensive: 100,
      adequate: 70,
      minimal: 40,
      none: 10,
    },
    investingStatus: {
      yes_active: 100,
      yes_passive: 75,
      starting: 50,
      no: 25,
    },
    retirementAccounts: {
      maxing: 100,
      contributing: 75,
      some: 40,
      no: 15,
    },
    financialGoals: {
      very_clear: 100,
      somewhat: 60,
      vague: 30,
      no: 10,
    },
    financialStress: {
      none: 100,
      low: 75,
      moderate: 50,
      high: 25,
      very_high: 10,
    },
    // Add more as needed
  };
  
  const key = questionKey.replace(/[0-9]/g, ''); // Remove trailing numbers
  const answerStr = Array.isArray(answer) ? answer[0] : String(answer);
  
  return scores[key]?.[answerStr] ?? 50; // Default to 50 if not found
}

// Calculate building block scores from responses
export function calculateBuildingBlockScores(
  responses: Record<string, string | string[] | number>
): Record<BuildingBlockKey, number> {
  const scores: Partial<Record<BuildingBlockKey, number[]>> = {};
  
  // Group scores by building block
  for (const question of FREE_ASSESSMENT_QUESTIONS) {
    if (question.section && responses[question.key] !== undefined) {
      const score = scoreAnswer(question.key, responses[question.key]);
      if (!scores[question.section]) {
        scores[question.section] = [];
      }
      scores[question.section]!.push(score);
    }
  }
  
  // Average each building block
  const buildingBlockScores: Record<BuildingBlockKey, number> = {
    income: 50,
    spending: 50,
    saving: 50,
    debt: 50,
    protection: 50,
    investing: 50,
    vision: 50,
  };
  
  for (const [block, blockScores] of Object.entries(scores)) {
    if (blockScores && blockScores.length > 0) {
      const avg = blockScores.reduce((a, b) => a + b, 0) / blockScores.length;
      buildingBlockScores[block as BuildingBlockKey] = Math.round(avg);
    }
  }
  
  return buildingBlockScores;
}

// Calculate pillar scores from building block scores
export function calculatePillarScores(
  buildingBlockScores: Record<BuildingBlockKey, number>
): Record<PillarKey, number> {
  const pillarScores: Record<PillarKey, number> = {
    clarity: 0,
    control: 0,
    stability: 0,
    security: 0,
    freedom: 0,
    growth: 0,
    legacy: 0,
  };
  
  for (const [pillar, blocks] of Object.entries(PILLAR_MAPPING)) {
    const blockScores = blocks.map(b => buildingBlockScores[b] || 0);
    pillarScores[pillar as PillarKey] = Math.round(
      blockScores.reduce((a, b) => a + b, 0) / blockScores.length
    );
  }
  
  return pillarScores;
}

// Calculate final Foundation Score
export function calculateScores(
  responses: Record<string, string | string[] | number>
): {
  foundationScore: number;
  buildingBlockScores: Record<BuildingBlockKey, number>;
  pillarScores: Record<PillarKey, number>;
  lifeStage: LifeStage;
} {
  const buildingBlockScores = calculateBuildingBlockScores(responses);
  const pillarScores = calculatePillarScores(buildingBlockScores);
  const foundationScore = calculateFoundationScore(pillarScores);
  
  // Determine life stage from responses
  const lifeStage = determineLifeStage({
    savingsLevel: parseInt(String(responses.emergencyFund || '0')) || 
      (responses.emergencyFundMonths === '6_plus' ? 6 : 
       responses.emergencyFundMonths === '3_6' ? 4.5 : 
       responses.emergencyFundMonths === '1_3' ? 2 : 0.5),
    investingActivity: responses.investingStatus === 'yes_active' || responses.investingStatus === 'yes_passive',
  });
  
  return {
    foundationScore,
    buildingBlockScores,
    pillarScores,
    lifeStage,
  };
}

// Generate insights based on scores
export function generateInsights(
  pillarScores: Record<PillarKey, number>,
  buildingBlockScores: Record<BuildingBlockKey, number>
): string[] {
  const insights: string[] = [];
  
  // Find lowest pillar
  const sortedPillars = Object.entries(pillarScores).sort((a, b) => a[1] - b[1]);
  const lowestPillar = sortedPillars[0];
  const highestPillar = sortedPillars[sortedPillars.length - 1];
  
  // Generate insight for lowest pillar
  const insightTemplates: Record<string, string> = {
    clarity: "Your clarity around income and financial purpose could use attention. Consider setting specific financial goals to gain direction.",
    control: "Your spending control is the priority area. Small changes in daily habits can make a big difference over time.",
    stability: "Building your savings buffer is key. Start with a small emergency fund and grow it incrementally.",
    security: "Your protection needs attention. Review your insurance coverage and build an emergency fund.",
    freedom: "Debt freedom is within reach. Focus on the highest-interest debt first for the fastest progress.",
    growth: "You're ready to grow your wealth. Ensure you're maximizing employer matches and starting regular investing.",
    legacy: "Your long-term vision needs clarity. Define what you want your financial legacy to look like.",
  };
  
  if (lowestPillar) {
    insights.push(insightTemplates[lowestPillar[0]] || `Focus on improving your ${PILLAR_LABELS[lowestPillar[0] as PillarKey]} pillar.`);
  }
  
  // Add positive insight
  if (highestPillar && highestPillar[1] > 70) {
    insights.push(`Great job on ${PILLAR_LABELS[highestPillar[0] as PillarKey]}! This strong foundation can help support other areas.`);
  }
  
  // Add automation insight
  if (buildingBlockScores.saving < 50 && buildingBlockScores.income > 60) {
    insights.push("Setting up automatic transfers to savings can help you build wealth without thinking about it.");
  }
  
  return insights.slice(0, 3);
}

// Generate prioritized actions
export function generatePriorities(
  pillarScores: Record<PillarKey, number>,
  buildingBlockScores: Record<BuildingBlockKey, number>,
  lifeStage: LifeStage
): string[] {
  const actions = determineNextBestActions(pillarScores, buildingBlockScores, lifeStage);
  return actions.map(a => a.action);
}

