export function generateReport(
  responses: Record<string, string | string[] | number>,
  reportType: AssessmentType
): ReportData {
  const { foundationScore, buildingBlockScores, pillarScores, lifeStage } = calculateScores(responses);
  const insights = generateInsights(pillarScores, buildingBlockScores);
  const priorities = generatePriorities(pillarScores, buildingBlockScores, lifeStage);
  
  // Generate action plan based on lowest areas
  const actionPlan: ActionPlan = {
    immediate: [],
    shortTerm: [],
    longTerm: [],
  };
  
  // Determine actions based on lowest building blocks
  const sortedBlocks = Object.entries(buildingBlockScores).sort((a, b) => a[1] - b[1]);
  
  if (sortedBlocks[0][0] === 'debt') {
    actionPlan.immediate.push("Review your debt and identify highest-interest balances");
    actionPlan.shortTerm.push("Create a debt paydown plan");
  }
  if (sortedBlocks[1][0] === 'saving') {
    actionPlan.immediate.push("Set up automatic transfer to savings");
    actionPlan.shortTerm.push("Build emergency fund to 1 month expenses");
  }
  if (sortedBlocks[2][0] === 'investing') {
    actionPlan.shortTerm.push("Open a retirement account if eligible");
    actionPlan.longTerm.push("Maximize employer 401(k) match");
  }
  
  // Add life stage specific actions
  if (lifeStage === 'starting_out') {
    actionPlan.immediate.push("Start tracking spending for 1 month");
    actionPlan.shortTerm.push("Build $500 starter emergency fund");
  } else if (lifeStage === 'growth') {
    actionPlan.shortTerm.push("Maximize tax-advantaged retirement accounts");
    actionPlan.longTerm.push("Increase savings rate to 15%+");
  }
  
  return {
    foundationScore,
    scoreBand: getScoreBand(foundationScore).label,
    lifeStage,
    buildingBlockScores,
    pillarScores,
    insights,
    priorities,
    actionPlan,
  };
}

