// Parse numeric value from responses (handles both direct numbers and range values)
function parseNumericValue(value: string | string[] | number | undefined): number {
  if (value === undefined || value === null) return 0;
  if (typeof value === 'number') return value;
  if (Array.isArray(value)) return parseFloat(value[0]) || 0;
  return parseFloat(value) || 0;
}

// Parse range values to approximate numbers
function parseRangeValue(value: string | string[] | number | undefined): number {
  if (value === undefined || value === null) return 0;
  if (typeof value === 'number') return value;
  
  const str = Array.isArray(value) ? value[0] : String(value);
  
  // Handle range mappings
  const rangeMappings: Record<string, number> = {
    'none': 0,
    'under_1k': 500,
    '1_5k': 3000,
    '5_10k': 7500,
    '10_20k': 15000,
    '20_50k': 35000,
    'over_50k': 75000,
    'under_100k': 50000,
    '100_250k': 175000,
    '250_500k': 375000,
    'over_500k': 750000,
    'under_10k': 5000,
    '10_30k': 20000,
    '30_60k': 45000,
    'over_60k': 90000,
    'under_1': 0.5,
    '1_3': 2,
    '3_6': 4.5,
    '6_plus': 9,
    'less_1': 0.5,
    'less_5': 2.5,
    '5_10': 7.5,
    '10_20': 15,
    '20_plus': 25,
    '20+': 25,
  };
  
  return rangeMappings[str] || 0;
}

// Calculate Debt-to-Income Ratio
export function calculateDTI(responses: Record<string, string | string[] | number>): number {
  // Handle both old and new income field names
  let monthlyIncome = parseNumericValue(responses.monthlyIncome);
  
  if (!monthlyIncome || monthlyIncome <= 0) {
    // Check new unified income fields
    const incomeType = responses.incomeType;
    const incomeAmount = parseNumericValue(responses.incomeAmount);
    
    if (incomeType === 'annual' && incomeAmount > 0) {
      monthlyIncome = incomeAmount / 12;
    } else if (incomeType === 'monthly' && incomeAmount > 0) {
      monthlyIncome = incomeAmount;
    } else if (incomeAmount > 0) {
      // Default to treating as monthly if type not specified
      monthlyIncome = incomeAmount;
    }
  }
  
  if (!monthlyIncome || monthlyIncome <= 0) {
    // Try annual income as fallback
    const annualIncome = parseNumericValue(responses.annualIncome);
    if (annualIncome > 0) {
      return calculateDTIFromAnnual(responses, annualIncome);
    }
    return 0; // Can't calculate without income
  }
  
  // Calculate monthly debt payments
  let monthlyDebt = 0;
  
  // Mortgage - check both old and new field formats
  const hasMortgage = responses.hasMortgage === 'yes';
  const mortgageBalance = parseNumericValue(responses.mortgageBalance) || parseRangeValue(responses.mortgageBalance);
  
  if (hasMortgage && mortgageBalance > 0) {
    const mortgageRate = parseRangeValue(responses.mortgageRate);
    // Estimate monthly payment (simplified)
    const rate = mortgageRate > 0 ? mortgageRate / 100 / 12 : 0.05 / 12;
    monthlyDebt += mortgageBalance * rate * 0.8; // Simplified
  }
  
  // Credit card debt (estimate minimum payments)
  const ccDebt = parseRangeValue(responses.creditCardDebt);
  if (ccDebt > 0) {
    monthlyDebt += ccDebt * 0.02; // Assume 2% minimum payment
  }
  
  // Student loans
  const studentDebt = parseRangeValue(responses.studentLoanBalance);
  if (studentDebt > 0) {
    monthlyDebt += studentDebt * 0.01; // Assume 1% payment
  }
  
  // Car loans
  const carDebt = parseRangeValue(responses.carLoanBalance);
  if (carDebt > 0) {
    monthlyDebt += carDebt * 0.03; // Assume 3% payment
  }
  
  if (monthlyIncome <= 0) return 0;
  return Math.round((monthlyDebt / monthlyIncome) * 100);
}

// Helper for annual income
function calculateDTIFromAnnual(responses: Record<string, string | string[] | number>, annualIncome: number): number {
  const monthlyIncome = annualIncome / 12;
  
  let monthlyDebt = 0;
  const ccDebt = parseRangeValue(responses.creditCardDebt);
  if (ccDebt > 0) monthlyDebt += ccDebt * 0.02;
  
  const studentDebt = parseRangeValue(responses.studentLoanBalance);
  if (studentDebt > 0) monthlyDebt += studentDebt * 0.01;
  
  const carDebt = parseRangeValue(responses.carLoanBalance);
  if (carDebt > 0) monthlyDebt += carDebt * 0.03;
  
  if (monthlyIncome <= 0) return 0;
  return Math.round((monthlyDebt / monthlyIncome) * 100);
}

// Calculate Savings Rate
export function calculateSavingsRate(responses: Record<string, string | string[] | number>): number {
  // Handle both old and new income field names
  let monthlyIncome = parseNumericValue(responses.monthlyIncome);
  
  if (!monthlyIncome || monthlyIncome <= 0) {
    const incomeType = responses.incomeType;
    const incomeAmount = parseNumericValue(responses.incomeAmount);
    
    if (incomeType === 'annual' && incomeAmount > 0) {
      monthlyIncome = incomeAmount / 12;
    } else if (incomeType === 'monthly' && incomeAmount > 0) {
      monthlyIncome = incomeAmount;
    } else if (incomeAmount > 0) {
      monthlyIncome = incomeAmount;
    }
  }
  
  if (!monthlyIncome || monthlyIncome <= 0) {
    const annualIncome = parseNumericValue(responses.annualIncome);
    if (annualIncome > 0) {
      return calculateSavingsRateFromAnnual(responses, annualIncome);
    }
    return 0;
  }
  
  // Calculate total savings (cash + investments)
  const savingsAmount = parseRangeValue(responses.totalSavings);
  const monthlyContribution = parseNumericValue(responses.monthlyContribution) || parseRangeValue(responses.monthlyContribution);
  
  const annualSavings = (savingsAmount * 0.1) + (monthlyContribution * 12); // Estimate annual savings
  const annualIncome = monthlyIncome * 12;
  
  if (annualIncome <= 0) return 0;
  return Math.min(100, Math.round((annualSavings / annualIncome) * 100));
}

function calculateSavingsRateFromAnnual(responses: Record<string, string | string[] | number>, annualIncome: number): number {
  const savingsAmount = parseRangeValue(responses.totalSavings);
  const monthlyContribution = parseNumericValue(responses.monthlyContribution) || parseRangeValue(responses.monthlyContribution);
  
  const annualSavings = (savingsAmount * 0.1) + (monthlyContribution * 12);
  
  if (annualIncome <= 0) return 0;
  return Math.min(100, Math.round((annualSavings / annualIncome) * 100));
}

// Calculate Estimated Net Worth
export function calculateNetWorth(responses: Record<string, string | string[] | number>): number {
  // Assets
  let assets = 0;
  assets += parseRangeValue(responses.totalSavings);
  assets += parseRangeValue(responses.totalInvestments);
  
  // Home equity (home value - mortgage)
  const homeValue = parseRangeValue(responses.homeValue) || parseNumericValue(responses.homeValue);
  const mortgageBalance = parseNumericValue(responses.mortgageBalance) || parseRangeValue(responses.mortgageBalance);
  if (homeValue > 0 && mortgageBalance > 0) {
    assets += Math.max(0, homeValue - mortgageBalance);
  } else if (homeValue > 0) {
    assets += homeValue;
  }
  
  // Additional property
  assets += parseRangeValue(responses.additionalPropertyValue);
  
  // Liabilities
  let liabilities = 0;
  liabilities += parseNumericValue(responses.mortgageBalance) || parseRangeValue(responses.mortgageBalance);
  liabilities += parseRangeValue(responses.creditCardDebt);
  liabilities += parseRangeValue(responses.studentLoanBalance);
  liabilities += parseRangeValue(responses.carLoanBalance);
  liabilities += parseRangeValue(responses.otherDebt);
  
  return assets - liabilities;
}

// Calculate Retirement Readiness
export function calculateRetirementReadiness(
  responses: Record<string, string | string[] | number>
): 'on_track' | 'moderate' | 'behind' {
  const age = String(responses.age || '');
  
  // Parse age to number
  let ageNum = 35; // Default
  if (age === 'under_25') ageNum = 22;
  else if (age === '25_35') ageNum = 30;
  else if (age === '35_45') ageNum = 40;
  else if (age === '45_55') ageNum = 50;
  else if (age === '55_65') ageNum = 60;
  else if (age === 'over_65') ageNum = 67;
  
  const totalInvestments = parseRangeValue(responses.totalInvestments);
  const savingsRate = parseRangeValue(responses.savingsRate);
  const monthlyContribution = parseNumericValue(responses.monthlyContribution) || parseRangeValue(responses.monthlyContribution);
  const employerMatch = responses.employerMatch;
  
  // Estimate retirement savings needed based on age
  const yearsToRetirement = 67 - ageNum;
  const annualIncome = parseNumericValue(responses.monthlyIncome) * 12 || 
    parseNumericValue(responses.annualIncome) || 50000;
  
  // Simple target: 25x annual expenses (4% rule)
  const targetRetirement = annualIncome * 25;
  
  // Current progress based on total investments
  const progress = targetRetirement > 0 ? (totalInvestments / targetRetirement) * 100 : 0;
  
  // Adjust target based on years to retirement
  const expectedProgressByAge = Math.min(100, ((67 - ageNum) / 45) * 100); // Linear by age
  
  // Additional factors
  const hasRetirementAccounts = responses.investingStatus === 'yes_active' || 
    responses.investingStatus === 'yes_passive' ||
    Array.isArray(responses.investmentAccounts) && responses.investmentAccounts.length > 0;
    
  const maximizingMatch = employerMatch === 'full_match';
  
  // Calculate readiness score
  let readinessScore = 0;
  
  // Progress toward target
  if (progress >= expectedProgressByAge) readinessScore += 40;
  else if (progress >= expectedProgressByAge * 0.7) readinessScore += 25;
  else if (progress >= expectedProgressByAge * 0.5) readinessScore += 10;
  
  // Retirement accounts
  if (hasRetirementAccounts) readinessScore += 20;
  
  // Employer match
  if (maximizingMatch) readinessScore += 15;
  
  // Savings rate
  if (savingsRate === '20_plus' || savingsRate === 'over_30') readinessScore += 25;
  else if (savingsRate === '10_20' || savingsRate === '20_30') readinessScore += 15;
  else if (savingsRate === '5_10') readinessScore += 5;
  
  if (readinessScore >= 60) return 'on_track';
  if (readinessScore >= 35) return 'moderate';
  return 'behind';
}

// Calculate Emergency Fund Months
export function calculateEmergencyFundMonths(responses: Record<string, string | string[] | number>): number {
  const emergencyFund = parseRangeValue(responses.emergencyFundMonths);
  if (emergencyFund > 0) return emergencyFund;
  
  // Try from detailed assessment
  const savings = parseRangeValue(responses.totalSavings);
  const monthlyExpenses = parseNumericValue(responses.monthlyExpenses) || 
    (parseNumericValue(responses.monthlyIncome) || 5000) * 0.8;
  
  if (monthlyExpenses <= 0) return 0;
  return Math.round(savings / monthlyExpenses);
}

// Calculate all financial metrics
export function calculateAllFinancialMetrics(
  responses: Record<string, string | string[] | number>
): FinancialMetrics {
  return {
    debtToIncomeRatio: calculateDTI(responses),
    savingsRate: calculateSavingsRate(responses),
    netWorth: calculateNetWorth(responses),
    retirementReadiness: calculateRetirementReadiness(responses),
    emergencyFundMonths: calculateEmergencyFundMonths(responses),
    // Handle both old and new income fields
    monthlyIncome: parseNumericValue(responses.monthlyIncome) || 
      (responses.incomeType === 'annual' ? parseNumericValue(responses.incomeAmount) / 12 :
       responses.incomeType === 'monthly' ? parseNumericValue(responses.incomeAmount) :
       parseNumericValue(responses.incomeAmount) || parseNumericValue(responses.annualIncome) / 12),
    totalSavings: parseNumericValue(responses.totalSavings) || parseRangeValue(responses.totalSavingsRange),
    totalInvestments: parseNumericValue(responses.totalInvestments) || parseRangeValue(responses.totalInvestmentsRange),
  };
}

// =====================================================
// ENHANCED SCORING LOGIC (CONDITIONAL)
// =====================================================

// Calculate building block scores with conditional logic
export function calculateEnhancedBuildingBlockScores(
  responses: Record<string, string | string[] | number>
): Record<BuildingBlockKey, number> {
  const scores = calculateBuildingBlockScores(responses);
  
  // Apply conditional scoring adjustments based on actual inputs
  
  // DEBT SCORING - Critical fix
  const debtTypes = responses.debtTypes;
  const hasMortgage = Array.isArray(debtTypes) ? debtTypes.includes('mortgage') : false;
  const hasCreditCards = Array.isArray(debtTypes) ? debtTypes.includes('credit_cards') : false;
  const hasPayday = Array.isArray(debtTypes) ? debtTypes.includes('payday') : false;
  const debtBurden = responses.debtBurden;
  
  if (hasPayday) {
    scores.debt = Math.max(0, scores.debt - 40); // Major penalty for payday loans
  } else if (hasCreditCards && debtBurden === 'struggling') {
    scores.debt = Math.max(0, scores.debt - 30);
  } else if (hasCreditCards && (debtBurden === 'tight' || debtBurden === 'comfortable')) {
    scores.debt = Math.max(0, scores.debt - 15);
  } else if (hasMortgage && !hasCreditCards && !hasPayday) {
    // Mortgage only - not penalized
    scores.debt = Math.max(scores.debt, 75); // Good score for mortgage only
  } else if (!hasCreditCards && !hasPayday && debtBurden === 'none') {
    scores.debt = Math.max(scores.debt, 90); // No debt = excellent
  }
  
  // PROTECTION SCORING - Emergency fund AND insurance
  const emergencyFundMonths = calculateEmergencyFundMonths(responses);
  const insuranceCoverage = responses.insuranceCoverage;
  
  if (emergencyFundMonths >= 6 && insuranceCoverage === 'comprehensive') {
    scores.protection = Math.max(scores.protection, 90);
  } else if (emergencyFundMonths >= 3 && (insuranceCoverage === 'comprehensive' || insuranceCoverage === 'adequate')) {
    scores.protection = Math.max(scores.protection, 75);
  } else if (emergencyFundMonths < 1 && (insuranceCoverage === 'minimal' || insuranceCoverage === 'none')) {
    scores.protection = Math.max(0, scores.protection - 25);
  }
  
  // INVESTING SCORING - Multiple accounts + consistency
  const investingStatus = responses.investingStatus;
  const investmentAccounts = responses.investmentAccounts;
  const monthlyContribution = responses.monthlyContribution;
  const employerMatch = responses.employerMatch;
  
  const hasMultipleAccounts = Array.isArray(investmentAccounts) && investmentAccounts.length >= 2;
  const hasConsistentContributions = monthlyContribution === 'over_2000' || 
    monthlyContribution === '1000_2000' || 
    monthlyContribution === '500_1000';
  const maximizingMatch = employerMatch === 'full_match';
  
  if (hasMultipleAccounts && hasConsistentContributions && maximizingMatch) {
    scores.investing = Math.max(scores.investing, 85);
  } else if (hasConsistentContributions) {
    scores.investing = Math.max(scores.investing, 70);
  } else if (investingStatus === 'yes_passive') {
    scores.investing = Math.max(scores.investing, 65);
  } else if (investingStatus === 'no') {
    scores.investing = Math.max(0, scores.investing - 20);
  }
  
  // SAVING SCORING - Strong rate AND emergency fund
  const savingsRate = calculateSavingsRate(responses);
  const automation = responses.automation;
  
  if (savingsRate >= 20 && emergencyFundMonths >= 6) {
    scores.saving = Math.max(scores.saving, 90);
  } else if (savingsRate >= 10 && emergencyFundMonths >= 3) {
    scores.saving = Math.max(scores.saving, 75);
  } else if (savingsRate < 5 || emergencyFundMonths < 1) {
    scores.saving = Math.max(0, scores.saving - 15);
  }
  
  // Boost for automation
  if (automation === 'yes_auto') {
    scores.saving = Math.min(100, scores.saving + 10);
  }
  
  return scores;
}

// =====================================================
// EXCLUSION LOGIC (Avoid duplicate recommendations)
// =====================================================

export interface ExclusionContext {
  hasEmergencyFund: boolean;
  hasRetirementAccounts: boolean;
  employerMatchMaximized: boolean;
  noHighInterestDebt: boolean;
  hasInsurance: boolean;
}

export function getExclusionContext(responses: Record<string, string | string[] | number>): ExclusionContext {
  const emergencyFundMonths = calculateEmergencyFundMonths(responses);
  
  const debtTypes = responses.debtTypes;
  const hasHighInterestDebt = Array.isArray(debtTypes) 
    ? debtTypes.includes('credit_cards') || debtTypes.includes('payday')
    : debtTypes === 'credit_cards' || debtTypes === 'payday';
  
  const investmentAccounts = responses.investmentAccounts;
  const hasRetirementAccounts = Array.isArray(investmentAccounts)
    ? investmentAccounts.some((a: string) => a.includes('401k') || a.includes('ira'))
    : false;
  
  const employerMatch = responses.employerMatch;
  
  const insuranceCoverage = responses.insuranceCoverage;
  
  return {
    hasEmergencyFund: emergencyFundMonths >= 3,
    hasRetirementAccounts,
    employerMatchMaximized: employerMatch === 'full_match',
    noHighInterestDebt: !hasHighInterestDebt,
    hasInsurance: insuranceCoverage === 'comprehensive' || insuranceCoverage === 'adequate',
  };
}

// Filter out already-completed actions from recommendations
export function filterExcludedActions(
  actions: string[], 
  exclusions: ExclusionContext
): string[] {
  return actions.filter(action => {
    const lowerAction = action.toLowerCase();
    
    // Emergency fund already satisfied
    if (exclusions.hasEmergencyFund && 
        (lowerAction.includes('emergency fund') || lowerAction.includes('build savings'))) {
      return false;
    }
    
    // Retirement accounts already exist
    if (exclusions.hasRetirementAccounts && 
        (lowerAction.includes('open retirement') || lowerAction.includes('retirement account'))) {
      return false;
    }
    
    // Employer match already maximized
    if (exclusions.employerMatchMaximized && lowerAction.includes('employer match')) {
      return false;
    }
    
    // No high-interest debt
    if (exclusions.noHighInterestDebt && 
        (lowerAction.includes('pay off debt') || lowerAction.includes('debt paydown') || 
         lowerAction.includes('high interest'))) {
      return false;
    }
    
    // Insurance already covered
    if (exclusions.hasInsurance && 
        (lowerAction.includes('insurance') || lowerAction.includes('coverage'))) {
      return false;
    }
    
    return true;
  });
}

// =====================================================
// ENHANCED NEXT BEST ACTION ENGINE
// =====================================================

export function determineEnhancedNextBestActions(
  pillarScores: Record<PillarKey, number>,
  buildingBlockScores: Record<BuildingBlockKey, number>,
  lifeStage: LifeStage,
  exclusions: ExclusionContext,
  metrics: FinancialMetrics
): PrioritizedAction[] {
  const actions: PrioritizedAction[] = [];
  
  // Rule: Stability before growth
  const stabilityPillar = pillarScores.stability || 0;
  const securityPillar = pillarScores.security || 0;
  
  // Determine highest risk
  const riskFactors: { factor: string; score: number; action: string }[] = [];
  
  // Debt risk
  if (!exclusions.noHighInterestDebt) {
    riskFactors.push({
      factor: 'debt',
      score: buildingBlockScores.debt,
      action: 'Address high-interest debt immediately'
    });
  }
  
  // Savings risk
  if (!exclusions.hasEmergencyFund) {
    riskFactors.push({
      factor: 'saving',
      score: buildingBlockScores.saving,
      action: 'Build emergency fund to 3 months expenses'
    });
  }
  
  // Protection risk
  if (!exclusions.hasInsurance) {
    riskFactors.push({
      factor: 'protection',
      score: buildingBlockScores.protection,
      action: 'Review insurance coverage'
    });
  }
  
  // Sort by score (lowest first = highest risk)
  riskFactors.sort((a, b) => a.score - b.score);
  
  // PRIMARY ACTION: Lowest score / highest risk
  if (riskFactors.length > 0) {
    actions.push({
      priority: 'primary',
      category: riskFactors[0].factor as BuildingBlockKey,
      action: riskFactors[0].action,
      reasoning: `This is your highest financial risk area. Addressing it first will have the biggest impact.`,
    });
  } else {
    // No major risks - focus on growth
    const growthPillar = pillarScores.growth || 0;
    actions.push({
      priority: 'primary',
      category: 'investing',
      action: 'Maximize tax-advantaged retirement accounts',
      reasoning: 'You have addressed your foundation. Now focus on wealth building.',
    });
  }
  
  // SECONDARY ACTIONS: Based on life stage and remaining low scores
  const sortedPillars = Object.entries(pillarScores).sort((a, b) => a[1] - b[1]);
  
  for (let i = 0; i < 2 && i < sortedPillars.length; i++) {
    if (sortedPillars[i][0] === riskFactors[0]?.factor) continue; // Skip already addressed
    
    const [pillar, score] = sortedPillars[i];
    
    // Don't recommend already completed actions
    const pillarActions = getPillarRecommendations(pillar, score, lifeStage, exclusions);
    const filteredActions = filterExcludedActions(pillarActions, exclusions);
    
    if (filteredActions.length > 0 && actions.length < 3) {
      actions.push({
        priority: 'secondary',
        category: pillar as PillarKey,
        action: filteredActions[0],
        reasoning: `Your ${PILLAR_LABELS[pillar as PillarKey]} pillar at ${score} could use attention.`,
      });
    }
  }
  
  // Add life stage specific secondary action if needed
  if (lifeStage === 'starting_out' && !exclusions.hasEmergencyFund) {
    if (actions.length < 3) {
      actions.push({
        priority: 'secondary',
        category: 'saving',
        action: 'Automate savings with direct deposit',
        reasoning: 'Starting Out stage: Building the habit of saving is crucial.',
      });
    }
  } else if (lifeStage === 'growth') {
    if (actions.length < 3) {
      actions.push({
        priority: 'secondary',
        category: 'investing',
        action: 'Increase savings rate to 15%+',
        reasoning: 'Growth stage: Maximize your wealth-building years.',
      });
    }
  }
  
  return actions.slice(0, 3); // Max 3 actions
}

function getPillarRecommendations(
  pillar: string, 
  score: number, 
  lifeStage: LifeStage,
  exclusions: ExclusionContext
): string[] {
  const recommendations: string[] = [];
  
  switch (pillar) {
    case 'stability':
      if (!exclusions.hasEmergencyFund) {
        recommendations.push('Build emergency fund to 3 months expenses');
      }
      break;
    case 'freedom':
      if (!exclusions.noHighInterestDebt) {
        recommendations.push('Create debt paydown plan');
      }
      break;
    case 'security':
      if (!exclusions.hasInsurance) {
        recommendations.push('Review insurance coverage needs');
      }
      break;
    case 'growth':
      if (!exclusions.hasRetirementAccounts) {
        recommendations.push('Open retirement account');
      }
      if (!exclusions.employerMatchMaximized) {
        recommendations.push('Maximize employer 401(k) match');
      }
      break;
    case 'control':
      recommendations.push('Track spending for one month');
      break;
    case 'clarity':
      recommendations.push('Define specific financial goals');
      break;
    case 'legacy':
      recommendations.push('Create estate plan or will');
      break;
  }
  
  return recommendations;
}

// =====================================================
// MILESTONE VALIDATION LOGIC
// =====================================================

export function calculateValidatedMilestones(
  responses: Record<string, string | string[] | number>
): { completed: string[]; remaining: string[] } {
  const completed: string[] = [];
  const remaining: string[] = [];
  
  const emergencyFundMonths = calculateEmergencyFundMonths(responses);
  const hasEmergencyFund = emergencyFundMonths >= 3;
  
  const debtTypes = responses.debtTypes;
  const hasHighInterestDebt = Array.isArray(debtTypes) 
    ? debtTypes.includes('credit_cards') || debtTypes.includes('payday')
    : false;
  
  const automation = responses.automation;
  const hasAutomation = automation === 'yes_auto';
  
  const insuranceCoverage = responses.insuranceCoverage;
  const hasBasicInsurance = insuranceCoverage === 'comprehensive' || 
    insuranceCoverage === 'adequate';
  
  const investingStatus = responses.investingStatus;
  const hasInvesting = investingStatus === 'yes_active' || investingStatus === 'yes_passive';
  
  // Starting Out milestones
  if (hasAutomation || responses.savingsRate) {
    completed.push('track_spending');
  } else {
    remaining.push('track_spending');
  }
  
  if (!hasHighInterestDebt) {
    completed.push('control_debt');
    completed.push('no_high_interest_debt');
  } else {
    remaining.push('control_debt');
    remaining.push('no_high_interest_debt');
  }
  
  if (hasEmergencyFund) {
    completed.push('starter_emergency');
    completed.push('three_month_emergency');
  } else {
    remaining.push('starter_emergency');
    if (emergencyFundMonths >= 0.5) {
      // Has some progress
    } else {
      remaining.push('three_month_emergency');
    }
  }
  
  // Stability milestones
  if (hasAutomation) {
    completed.push('consistent_saving');
  } else {
    remaining.push('consistent_saving');
  }
  
  if (hasBasicInsurance) {
    completed.push('basic_insurance');
  } else {
    remaining.push('basic_insurance');
  }
  
  // Growth milestones
  if (hasInvesting) {
    completed.push('regular_investing');
  } else {
    remaining.push('regular_investing');
  }
  
  const investmentAccounts = responses.investmentAccounts;
  const hasRetirement = Array.isArray(investmentAccounts) && 
    investmentAccounts.some(a => a.includes('401k') || a.includes('ira'));
  
  if (hasRetirement) {
    completed.push('retirement_funded');
  } else {
    remaining.push('retirement_funded');
  }
  
  const savingsRate = calculateSavingsRate(responses);
  if (savingsRate >= 10) {
    completed.push('meaningful_savings_rate');
  } else {
    remaining.push('meaningful_savings_rate');
  }
  
  return { completed, remaining };
}

// =====================================================
// RETIREMENT & ASSET AWARENESS FOR 40+ USERS
// =====================================================

export function calculateAgeAdjustedScores(
  buildingBlockScores: Record<BuildingBlockKey, number>,
  pillarScores: Record<PillarKey, number>,
  responses: Record<string, string | string[] | number>
): { buildingBlockScores: Record<BuildingBlockKey, number>; pillarScores: Record<PillarKey, number> } {
  const age = String(responses.age || '');
  const isOver40 = age === '35_45' || age === '45_55' || age === '55_65' || age === 'over_65';
  
  if (!isOver40) {
    return { buildingBlockScores, pillarScores };
  }
  
  // Clone to avoid mutation
  const adjustedBB = { ...buildingBlockScores };
  const adjustedPillar = { ...pillarScores };
  
  // For 40+, evaluate additional factors
  const totalInvestments = parseRangeValue(responses.totalInvestments);
  const totalSavings = parseRangeValue(responses.totalSavings);
  const homeValue = parseRangeValue(responses.homeValue);
  const additionalProperty = parseRangeValue(responses.additionalPropertyValue);
  
  const totalAssets = totalInvestments + totalSavings + homeValue + additionalProperty;
  
  // Adjust Growth score based on assets
  if (totalAssets > 500000) {
    adjustedBB.investing = Math.min(100, adjustedBB.investing + 15);
    adjustedPillar.growth = Math.min(100, adjustedPillar.growth + 10);
  } else if (totalAssets > 200000) {
    adjustedBB.investing = Math.min(100, adjustedBB.investing + 10);
    adjustedPillar.growth = Math.min(100, adjustedPillar.growth + 5);
  }
  
  // Adjust Legacy score based on preparation
  const retirementReadiness = calculateRetirementReadiness(responses);
  if (retirementReadiness === 'on_track') {
    adjustedPillar.legacy = Math.min(100, adjustedPillar.legacy + 20);
  } else if (retirementReadiness === 'moderate') {
    adjustedPillar.legacy = Math.min(100, adjustedPillar.legacy + 10);
  }
  
  return { buildingBlockScores: adjustedBB, pillarScores: adjustedPillar };
}

// =====================================================
// DISPLAY CALCULATIONS IN REPORTS
// =====================================================

export function formatMetricForReport(
  metricName: string,
  metrics: FinancialMetrics,
  reportType: AssessmentType
): MetricDisplay | null {
  if (reportType === 'free') return null; // Don't show in free report
  
  switch (metricName) {
    case 'dti':
      if (metrics.debtToIncomeRatio === undefined) return null;
      const dtiRating: MetricRating = metrics.debtToIncomeRatio <= 15 ? 'strong' : 
        metrics.debtToIncomeRatio <= 36 ? 'moderate' : 'needs_improvement';
      return {
        value: `${metrics.debtToIncomeRatio}%`,
        rating: dtiRating,
        label: dtiRating === 'strong' ? 'Healthy DTI' : 
          dtiRating === 'moderate' ? 'Moderate DTI' : 'High DTI',
        explanation: dtiRating === 'strong' 
          ? 'Your debt payments are well within healthy limits.'
          : dtiRating === 'moderate'
            ? 'Your debt level is manageable but could be improved.'
            : 'Consider reducing debt to improve your financial health.',
      };
      
    case 'savingsRate':
      if (metrics.savingsRate === undefined) return null;
      const srRating: MetricRating = metrics.savingsRate >= 20 ? 'strong' : 
        metrics.savingsRate >= 10 ? 'moderate' : 'needs_improvement';
      return {
        value: `${metrics.savingsRate}%`,
        rating: srRating,
        label: srRating === 'strong' ? 'Excellent Savings Rate' : 
          srRating === 'moderate' ? 'Moderate Savings Rate' : 'Low Savings Rate',
        explanation: srRating === 'strong'
          ? 'You are saving a significant portion of your income.'
          : srRating === 'moderate'
            ? 'Room to increase savings rate for better financial security.'
            : 'Aim to save at least 10% of your income for long-term stability.',
      };
      
    case 'netWorth':
      if (reportType !== 'premium') return null;
      if (metrics.netWorth === undefined) return null;
      const nwRating: MetricRating = metrics.netWorth >= 100000 ? 'strong' : 
        metrics.netWorth >= 0 ? 'moderate' : 'needs_improvement';
      return {
        value: `$${metrics.netWorth.toLocaleString()}`,
        rating: nwRating,
        label: nwRating === 'strong' ? 'Positive Net Worth' : 
          nwRating === 'moderate' ? 'Building Net Worth' : 'Negative Net Worth',
        explanation: nwRating === 'strong'
          ? 'You have built significant assets relative to liabilities.'
          : nwRating === 'moderate'
            ? 'You are making progress building wealth.'
            : 'Focus on reducing debt and increasing assets.',
      };
      
    case 'retirement':
      if (reportType !== 'premium') return null;
      if (!metrics.retirementReadiness) return null;
      const rrLabel = metrics.retirementReadiness === 'on_track' ? 'On Track' :
        metrics.retirementReadiness === 'moderate' ? 'Moderate Progress' : 'Needs Attention';
      return {
        value: rrLabel,
        rating: metrics.retirementReadiness === 'on_track' ? 'strong' :
          metrics.retirementReadiness === 'moderate' ? 'moderate' : 'needs_improvement',
        label: `Retirement: ${rrLabel}`,
        explanation: metrics.retirementReadiness === 'on_track'
          ? 'You are well-positioned for retirement.'
          : metrics.retirementReadiness === 'moderate'
            ? 'Consider increasing retirement contributions.'
            : 'Priority should be given to retirement savings.',
      };
      
    default:
      return null;
  }
}

