export function calculateWealthScore(pillarScores: Record<string, number>): number {
  const validScores = Object.values(pillarScores);
  const avg = validScores.reduce((a, b) => a + b, 0) / validScores.length;
  return Math.round(300 + (avg / 100) * 550);
}

export function generateRecommendations(pillarScores: Record<PillarKey, number>): string[] {
  const recommendations: string[] = [];
  
  if (pillarScores.stability < 60) {
    recommendations.push("Focus on building your emergency fund to 3-6 months of expenses");
  }
  if (pillarScores.freedom < 60) {
    recommendations.push("Prioritize paying off high-interest debt");
  }
  if (pillarScores.growth < 60) {
    recommendations.push("Start investing consistently, even with small amounts");
  }
  
  return recommendations;
}

