import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { useEffect, useRef, useState } from 'react';
import { client } from './api/client';
import { useAppStore } from './store/appStore';
import { api } from './api/client';

// Pages
import LandingPage from './pages/LandingPage';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import SnapshotQuestionnaire from './pages/SnapshotQuestionnaire';
import ComprehensiveQuestionnaire from './pages/ComprehensiveQuestionnaire';
import ResultsPage from './pages/ResultsPage';
import ScheduleConsultation from './pages/ScheduleConsultation';
import PricingPage from './pages/PricingPage';
import ArticlesPage from './pages/ArticlesPage';
import ArticleDetailPage from './pages/ArticleDetailPage';
import NewArticlePage from './pages/NewArticlePage';
import FoundationScorePage from './pages/FoundationScorePage';
import PremiumPage from './pages/PremiumPage';
import BuildingBlocksPage from './pages/BuildingBlocksPage';
import FinancialPillarsPage from './pages/FinancialPillarsPage';
import NewsletterPage from './pages/NewsletterPage';

function App() {
  const { isAuthenticated, isChecking, setAuth, setUser, setCurrentAssessment, setAssessmentHistory } = useAppStore();
  const [authChecked, setAuthChecked] = useState(false);
  const authContainerRef = useRef<HTMLDivElement>(null);
  const hasRenderedAuth = useRef(false);

  useEffect(() => {
    checkAuth();
  }, []);

  async function checkAuth() {
    try {
      const session = await client.auth.getSession();
      if (session.data?.user) {
        setAuth(true, false);
        setUser({
          id: 0,
          userId: session.data.user.id,
          name: session.data.user.name || null,
          email: session.data.user.email || null,
          isPremium: 0,
          subscriptionStatus: 'free',
          createdAt: null,
          updatedAt: null,
        });
        // Load user data
        try {
          console.log('[Auth] Loading user profile and assessments...');
          const profile = await api.getProfile();
          setUser(profile.profile);
          console.log('[Auth] Profile loaded:', profile.profile);
          
          const latest = await api.getLatestAssessment();
          console.log('[Auth] Latest assessment:', latest.assessment);
          if (latest.assessment) {
            setCurrentAssessment(latest.assessment);
          }
          
          const history = await api.getAssessments();
          console.log('[Auth] Assessment history:', history.assessments?.length, 'assessments');
          setAssessmentHistory(history.assessments);
        } catch (e) {
          console.error('[Auth] Failed to load user data:', e);
        }
      } else {
        setAuth(false, false);
      }
    } catch (e) {
      setAuth(false, false);
    }
    setAuthChecked(true);
  }

  async function handleLogout() {
    await client.auth.signOut();
    setAuth(false, false);
    setUser(null);
    setCurrentAssessment(null);
    setAssessmentHistory([]);
  }

  if (!authChecked) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-slate-400">Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <BrowserRouter>
      <Routes>
        {/* Public routes */}
        <Route path="/" element={<LandingPage />} />
        <Route path="/building-blocks" element={<BuildingBlocksPage />} />
        <Route path="/financial-pillars" element={<FinancialPillarsPage />} />
        <Route path="/foundation-score" element={<FoundationScorePage />} />
        <Route path="/premium" element={<PremiumPage />} />
        <Route path="/newsletter" element={<NewsletterPage />} />
        <Route 
          path="/login" 
          element={
            isAuthenticated ? 
              <Navigate to="/my-foundation" replace /> : 
              <LoginPage onSuccess={() => checkAuth()} />
          } 
        />

        {/* Protected routes */}
        <Route 
          path="/my-foundation" 
          element={
            isAuthenticated ? 
              <DashboardPage onLogout={handleLogout} /> : 
              <Navigate to="/login" replace />
          } 
        />
        <Route 
          path="/assessment/snapshot" 
          element={
            isAuthenticated ? 
              <SnapshotQuestionnaire /> : 
              <Navigate to="/login" replace />
          } 
        />
        <Route 
          path="/assessment/comprehensive" 
          element={
            isAuthenticated ? 
              <ComprehensiveQuestionnaire /> : 
              <Navigate to="/login" replace />
          } 
        />
        <Route 
          path="/results" 
          element={
            isAuthenticated ? 
              <ResultsPage /> : 
              <Navigate to="/login" replace />
          } 
        />
        <Route 
          path="/consultation" 
          element={
            isAuthenticated ? 
              <ScheduleConsultation /> : 
              <Navigate to="/login" replace />
          } 
        />
        <Route 
          path="/pricing" 
          element={
            isAuthenticated ? 
              <PricingPage /> : 
              <Navigate to="/login" replace />
          } 
        />

        {/* Public Article routes */}
        <Route path="/articles" element={<ArticlesPage />} />
        <Route path="/articles/new" element={<NewArticlePage />} />
        <Route path="/articles/:id" element={<ArticleDetailPage />} />

        {/* Fallback */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
