import { useEffect, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { client } from '../api/client';
import { useAppStore } from '../store/appStore';
import logoImage from '../assets/house-icon.png';

interface LoginPageProps {
  onSuccess: () => void;
}

export default function LoginPage({ onSuccess }: LoginPageProps) {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { setAuth, setUser } = useAppStore();
  const containerRef = useRef<HTMLDivElement>(null);
  const hasRenderedAuth = useRef(false);

  // Get redirect path from URL params
  const redirectPath = searchParams.get('redirect') || '/my-foundation';

  useEffect(() => {
    if (containerRef.current && !hasRenderedAuth.current) {
      hasRenderedAuth.current = true;
      renderAuthUI();
    }
  }, []);

  async function renderAuthUI() {
    if (!containerRef.current) return;

    await client.auth.renderAuthUI(containerRef.current, {
      redirectTo: redirectPath,
      labels: {
        signIn: {
          title: 'Welcome Back',
          subtitle: 'Sign in to continue your financial journey',
          loginButton: 'Sign In',
        },
        signUp: {
          title: 'Create Account',
          subtitle: 'Start building your wealthy foundation',
          signUpButton: 'Get Started',
        },
      },
      onLogin: (user) => {
        console.log('User logged in:', user);
        onSuccess();
        // Navigate to the intended destination
        navigate(redirectPath);
      },
    });
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <img src={logoImage} alt="A Wealthy Foundation" className="h-16 w-auto mx-auto mb-4" />
          <p className="text-slate-400">Sign in to access your dashboard</p>
        </div>
        
        <div 
          ref={containerRef}
          className="bg-white rounded-2xl p-6 shadow-xl"
          style={{ minHeight: '300px' }}
        />
        
        <div className="mt-6 text-center">
          <button
            onClick={() => navigate('/')}
            className="text-slate-400 hover:text-white transition-colors text-sm"
          >
            ← Back to home
          </button>
        </div>
      </div>
    </div>
  );
}
